# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

import decimal

def process_transactions(transactions, account_balances):
    """
    Processes a list of financial transactions and updates account balances.

    Args:
        transactions: A list of dictionaries, where each dictionary represents a transaction.
                      Each transaction dictionary should have the following keys:
                      - 'from_account': The account ID from which money is debited.
                      - 'to_account': The account ID to which money is credited.
                      - 'amount': The amount of the transaction (decimal.Decimal).
                      - 'transaction_id': A unique identifier for the transaction (optional).
        account_balances: A dictionary where keys are account IDs (strings) and values are
                          their current balances (decimal.Decimal). This dictionary will be
                          modified in place.

    Returns:
        A boolean indicating if all transactions were processed successfully.
        Returns False if any account involved in a transaction does not exist
        or if an overdraft would occur.

    Raises:
        ValueError: If a transaction amount is negative.
        TypeError: If transaction amount is not decimal.Decimal.
    """
    for transaction in transactions:
        from_account = transaction['from_account']
        to_account = transaction['to_account']
        amount = transaction['amount']

        if not isinstance(amount, decimal.Decimal):
            raise TypeError(f"Transaction amount must be decimal.Decimal, got {type(amount)}")
        if amount < 0:
            raise ValueError("Transaction amount cannot be negative.")

        if from_account not in account_balances:
            print(f"Error: 'from_account' {from_account} not found.")
            return False
        if to_account not in account_balances:
            print(f"Error: 'to_account' {to_account} not found.")
            return False

        if account_balances[from_account] < amount:
            print(f"Error: Insufficient funds in account {from_account} for transaction of {amount}.")
            return False

        account_balances[from_account] -= amount
        account_balances[to_account] += amount

    return True